const fs = require('fs');
const path = require('path');
const requestId = $('Generate Request ID').first().json.requestId;
const tempPath = path.join('/tmp', `n8n_${requestId}.json`);

let workoutPlan;
try {
  const rawOutput = $input.first().json.output;
  const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
  workoutPlan = JSON.parse(jsonMatch ? jsonMatch[0] : rawOutput);
} catch (e) {
  if (fs.existsSync(tempPath)) {
    fs.writeFileSync(tempPath, JSON.stringify({
      status: 'error',
      error: 'Failed to parse workout plan JSON: ' + e.message
    }));
  }
  return [{ json: { success: false, error: e.message } }];
}

fs.writeFileSync(tempPath, JSON.stringify({
  status: 'completed',
  workoutPlan: workoutPlan,
  completedAt: new Date().toISOString()
}));

return [{ json: { success: true, requestId } }];

const fs = require('fs');
const path = require('path');
const requestId = $input.first().json.query.requestId;

if (!requestId) {
  return [{ json: { status: 'error', error: 'Missing requestId' } }];
}

const tempPath = path.join('/tmp', `n8n_${requestId}.json`);

if (!fs.existsSync(tempPath)) {
  return [{ json: { status: 'error', error: 'Invalid or unknown requestId' } }];
}

const data = JSON.parse(fs.readFileSync(tempPath, 'utf8'));

if (data.status === 'completed' || data.status === 'error') {
  try {
    fs.unlinkSync(tempPath);
  } catch (e) {
    console.error('Failed to delete temp file:', e);
  }
}

return [{ json: data }];
